import { Component, OnInit } from '@angular/core';
import * as $ from 'jquery';
import { DOCUMENT } from '@angular/common';
import { Route, Router } from '@angular/router';
import { LocalStoreService } from 'src/app/shared/services/local-store.service';
import { ApiService } from 'src/app/shared/services/api.service';

@Component({
  selector: 'npr-header',
  templateUrl: './header.component.html',
  styleUrls: ['./header.component.scss']
})
export class HeaderComponent implements OnInit {
  user: any;
  department: string;
  departmentString: string;
  currentUser: string;
  currentUserString: string;
  pendingForAuthData: any;
  changeText: boolean;
  changeText2: boolean;
  changeText1: boolean;
  notToShowAll: boolean = true;
  constructor(private localStoreService: LocalStoreService, private api: ApiService,
    private router: Router) { }

  ngOnInit(): void {
    this.user = localStorage.getItem("userFromLogin")
    this.department=localStorage.getItem("departmentHeader")
    this.departmentString= this.department.replace(/["]+/g, '')
    this.currentUser=localStorage.getItem("LoggedInUserHeader")
     this.currentUserString= this.currentUser.replace(/["]+/g, '')
     this.getPendingForAuthData();
  }

  openPopUp() {
    $(document).on('click', '.ddTrigger', function (e) {
      $('.ddParent').removeClass('actDD');
      $(this).parents('li').siblings().find('.ddParent').removeClass('actDD');
      $(this).parents('.ddParent').toggleClass('actDD');
      $(this).removeClass('actUnread');
    });
  }

  closeAll() {
    $(document).on("click", function (event: any) {
      var $trigger = $(".ddParent");
      if ($trigger !== event.target && !$trigger.has(event.target).length) {
        $(".ddParent").removeClass("actDD");
      }
    });
  }

  close() {
    $(document).on('click', '.ddCloseTrigger', function (e) {
      $(".ddParent").removeClass("actDD");
    });
  }

  changeTheme() {
    var lastBg = "";
    $(document).on('click', '.tColor', function (e) {
      e.preventDefault();
      var bgClass = $(this).data("id");
      $(this).addClass('active').parent().siblings().find('.tColor').removeClass('active');
      $('body').removeClass(lastBg).addClass(bgClass);
      lastBg = bgClass;
      $('.ddParent').removeClass('actDD');
    });
  }

  logOut() {
    $(".ddParent").removeClass("actDD");
    this.localStoreService.clear();
    sessionStorage.clear();
    localStorage.clear();
    this.router.navigate(['session/login']);
  }

  changePassword() {
    $(".ddParent").removeClass("actDD");
    this.router.navigate(['change-password']);
  }
  getPendingForAuthData() {
    this.api.getPendingForAuthDataFirstError(this.user).subscribe(resp => {
      // console.log(resp);
      this.pendingForAuthData = resp;
      console.log(this.pendingForAuthData);
    });
  }
}
