import { Component, HostListener, Inject, Renderer2 } from "@angular/core";
import { DOCUMENT } from "@angular/common";
import { Platform } from "@angular/cdk/platform";
import { ActivatedRoute } from "@angular/router";
import { Subject } from "rxjs";
import { Router } from '@angular/router';
import Swal from 'sweetalert2';
@Component({
  selector: "app-root",
  templateUrl: "./app.component.html",
  styleUrls: ["./app.component.scss"],
})
export class AppComponent {
  title = "Median";
  userActivity: any;
  userInactive: Subject<any> = new Subject();
  constructor(
    
    private renderer: Renderer2,
    private platform: Platform,
    @Inject(DOCUMENT) private document: Document,
    private route: ActivatedRoute,
    private router: Router) {
      this.setTimeout();
      this.userInactive.subscribe(() => this.logout());}

      setTimeout() {
        this.userActivity = setTimeout(
          () => this.userInactive.next(undefined),
          600 * 1000
        );
  }

  logout() {
    if (localStorage.getItem("userFromLogin")) {
      Swal.fire("Session Expired", "Kindly Login to continue.");
    }
    localStorage.clear();
    sessionStorage.clear();
    this.router.navigate(['/session/login']);
  }

  @HostListener("window:mousemove") refreshUserState() {
    clearTimeout(this.userActivity);
    this.setTimeout();
  }

  @HostListener("window:storage") onUpdateStorage() {
    const getOtpClicked = localStorage.getItem("getOtpClicked");
    if(getOtpClicked==='true') {
      localStorage.clear();
      sessionStorage.clear();
      this.router.navigate(['/session/login']);
    }
  }
}
